___CSS_LOADER_EXPORT___.push([module.id, `/* AdminPages.css */
.admin-page {
    animation: fadeIn 0.3s ease-out;
}

.page-header {
    margin-bottom: 32px;
}

.page-header h1 {
    font-size: 28px;
    color: var(--gray-800);
    margin-bottom: 8px;
}

.page-header p {
    color: var(--gray-500);
    margin-bottom: 20px;
}

.page-kicker {
    display: inline-flex;
    align-items: center;
    padding: 6px 12px;
    margin-bottom: 10px;
    border-radius: 999px;
    background: rgba(99, 102, 241, 0.12);
    color: var(--primary-color);
    font-size: 12px;
    font-weight: 700;
    letter-spacing: 0.04em;
    text-transform: uppercase;
}

/* Stats Badges */
.users-stats, .formateurs-stats {
    display: flex;
    gap: 16px;
    margin-bottom: 24px;
    flex-wrap: wrap;
}

.stat-badge {
    background: var(--surface);
    padding: 8px 16px;
    border-radius: 20px;
    box-shadow: var(--box-shadow-sm);
    font-size: 14px;
}

/* Table Styles */
.table-container {
    overflow-x: auto;
    background: var(--surface);
    border-radius: var(--border-radius);
    box-shadow: var(--box-shadow);
    padding: 20pxs;
}

.data-table {
    width: 100%;
    border-collapse: collapse;
}

.data-table th,
.data-table td {
    padding: 16px;
    text-align: left;
    border-bottom: 1px solid var(--gray-200);
}

.data-table th {
    background: var(--gray-50);
    font-weight: 600;
    color: var(--gray-600);
    font-size: 14px;
}

.data-table tbody tr:hover {
    background: var(--gray-50);
}

/* Badges */
.badge {
    display: inline-block;
    padding: 4px 12px;
    border-radius: 20px;
    font-size: 12px;
    font-weight: 600;
}

.badge-admin {
    background: #8B5CF6;
    color: white;
}

.badge-formateur {
    background: #3B82F6;
    color: white;
}

.badge-etudiant {
    background: #10B981;
    color: white;
}

.badge-success {
    background: #10B981;
    color: white;
}

/* Password Status */
.password-status {
    font-size: 12px;
    padding: 4px 8px;
    border-radius: 12px;
}

.has-password {
    color: #10B981;
}

.no-password {
    color: #EF4444;
}

/* Modules Grid */
.modules-grid {
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.niveau-section {
    background: var(--surface);
    border-radius: var(--border-radius);
    padding: 24px;
    box-shadow: var(--box-shadow);
}

.niveau-title {
    font-size: 20px;
    margin-bottom: 20px;
    padding-left: 16px;
    border-left: 4px solid;
}

.module-cards {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 16px;
}

.module-overview-strip {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 14px;
    margin-bottom: 24px;
}

.overview-card {
    background: linear-gradient(180deg, rgba(255,255,255,0.96), rgba(248,250,252,0.96));
    border: 1px solid var(--gray-200);
    border-radius: var(--border-radius);
    padding: 16px 18px;
    box-shadow: var(--box-shadow-sm);
}

.overview-value {
    display: block;
    font-size: 20px;
    font-weight: 800;
    color: var(--gray-900);
    margin-bottom: 4px;
}

.overview-label {
    display: block;
    font-size: 13px;
    color: var(--gray-500);
}

.module-card {
    background: var(--gray-50);
    border-radius: var(--border-radius-sm);
    padding: 16px;
    transition: var(--transition);
}

.module-card:hover {
    transform: translateY(-2px);
    box-shadow: var(--box-shadow-md);
}

.module-code {
    font-family: monospace;
    font-size: 12px;
    color: var(--primary-color);
    margin-bottom: 8px;
}

.module-name {
    font-weight: 600;
    margin-bottom: 8px;
}

.module-meta {
    display: flex;
    gap: 16px;
    font-size: 12px;
    color: var(--gray-500);
    margin-bottom: 8px;
}

.module-desc {
    font-size: 13px;
    color: var(--gray-600);
}

.admin-module-detail {
    position: relative;
    overflow: hidden;
    background: linear-gradient(180deg, #ffffff 0%, #f8fafc 100%);
    border: 1px solid rgba(148, 163, 184, 0.22);
    box-shadow: var(--box-shadow);
}

.module-card-accent {
    height: 5px;
    width: 100%;
    background: linear-gradient(90deg, #2563eb 0%, #0ea5e9 50%, #22c55e 100%);
}

.component-chip-row {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 10px;
}

.component-chip {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 6px 10px;
    border-radius: 999px;
    background: rgba(37, 99, 235, 0.1);
    color: #1d4ed8;
    font-size: 12px;
    font-weight: 700;
}

/* Assignment Form */
.assignment-form {
    background: var(--surface);
    border-radius: var(--border-radius);
    padding: 24px;
    margin-bottom: 32px;
    box-shadow: var(--box-shadow);
}

.assignment-form h2,
.assignments-list h2,
.enrollments-list h2 {
    font-size: 18px;
    margin-bottom: 20px;
    color: var(--gray-800);
}

/* Modal */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.modal-content {
    background: var(--surface);
    border-radius: var(--border-radius-lg);
    width: 90%;
    max-width: 500px;
    max-height: 90vh;
    overflow-y: auto;
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 20px 24px;
    border-bottom: 1px solid var(--gray-200);
}

.modal-close {
    background: none;
    border: none;
    font-size: 24px;
    cursor: pointer;
    color: var(--gray-500);
}

.modal-body {
    padding: 24px;
}

.modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 12px;
    padding: 20px 24px;
    border-top: 1px solid var(--gray-200);
}

/* Form Row */
.form-row {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 16px;
}

.form-input,
.form-select,
.form-textarea {
    width: 100%;
    padding: 12px;
    border: 2px solid var(--gray-200);
    border-radius: var(--border-radius-sm);
    font-size: 14px;
    transition: var(--transition);
}

.form-input:focus,
.form-select:focus,
.form-textarea:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.1);
}

/* Alert */
.alert {
    padding: 12px 16px;
    border-radius: var(--border-radius-sm);
    margin-bottom: 20px;
}

.alert-success {
    background: #ecfdf5;
    color: #047857;
    border: 1px solid #a7f3d0;
}

.alert-error {
    background: #fef2f2;
    color: #dc2626;
    border: 1px solid #fecaca;
}

/* Loading */
.loading-text {
    text-align: center;
    padding: 60px;
    color: var(--gray-500);
}

/* Responsive */
@media (max-width: 768px) {
    .form-row {
        grid-template-columns: 1fr;
    }
    
    .module-cards {
        grid-template-columns: 1fr;
    }
    
    .data-table th,
    .data-table td {
        padding: 12px;
        font-size: 13px;
    }
}
/* Action buttons */
.btn-icon {
    background: none;
    border: none;
    font-size: 18px;
    cursor: pointer;
    padding: 6px;
    border-radius: 8px;
    transition: var(--transition);
    margin: 0 2px;
}

.btn-icon:hover {
    background: var(--gray-100);
    transform: scale(1.1);
}

.btn-icon.btn-danger:hover {
    background: #fee2e2;
    color: var(--danger-color);
}

.module-actions {
    display: flex;
    gap: 8px;
    margin-top: 12px;
    justify-content: flex-end;
}

/* Add to table actions cell */
.data-table td:last-child {
    white-space: nowrap;
}

.modules-admin-list {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

/* Grille 4 colonnes pour les modules admin */
.modules-admin-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 20px;
    align-items: start;
}

@media (max-width: 1400px) {
    .modules-admin-grid { grid-template-columns: repeat(3, 1fr); }
}
@media (max-width: 1000px) {
    .modules-admin-grid { grid-template-columns: repeat(2, 1fr); }
}
@media (max-width: 640px) {
    .modules-admin-grid { grid-template-columns: 1fr; }
}

/* Barre de filtres */
.filters-bar {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    align-items: center;
    padding: 12px 16px;
    background: var(--gray-50);
    border-bottom: 1px solid var(--gray-200);
}

.filters-bar label {
    font-size: 13px;
    font-weight: 600;
    color: var(--gray-600);
    white-space: nowrap;
}

.filter-select {
    padding: 7px 12px;
    border: 2px solid var(--gray-200);
    border-radius: var(--border-radius-sm);
    font-size: 13px;
    background: var(--surface);
    min-width: 160px;
    cursor: pointer;
    transition: var(--transition);
}

.filter-select:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.1);
}

.admin-module-detail {
    background: var(--surface);
    border-radius: var(--border-radius);
    padding: 20px;
    box-shadow: var(--box-shadow);
}

.module-card-head {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 16px;
}

.resource-type-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 12px;
    margin-top: 16px;
}

.resource-type-cell {
    background: var(--gray-100);
    border-radius: 8px;
    padding: 10px;
    text-align: center;
}

.resource-type-label {
    display: block;
    font-size: 12px;
    color: var(--gray-600);
    margin-bottom: 4px;
}

.resource-type-count {
    font-size: 20px;
    font-weight: 700;
    color: var(--gray-900);
}

.resource-mini-list {
    margin: 12px 0 0;
    padding-left: 18px;
    font-size: 14px;
    color: var(--gray-700);
}

.resource-mini-list .r-cat {
    display: inline-block;
    min-width: 4.5rem;
    font-size: 12px;
    color: var(--gray-500);
}
`, "",{"version":3,"sources":["webpack://./src/pages/admin/AdminPages.css"],"names":[],"mappings":"AAAA,mBAAmB;AACnB;IACI,+BAA+B;AACnC;;AAEA;IACI,mBAAmB;AACvB;;AAEA;IACI,eAAe;IACf,sBAAsB;IACtB,kBAAkB;AACtB;;AAEA;IACI,sBAAsB;IACtB,mBAAmB;AACvB;;AAEA;IACI,oBAAoB;IACpB,mBAAmB;IACnB,iBAAiB;IACjB,mBAAmB;IACnB,oBAAoB;IACpB,oCAAoC;IACpC,2BAA2B;IAC3B,eAAe;IACf,gBAAgB;IAChB,sBAAsB;IACtB,yBAAyB;AAC7B;;AAEA,iBAAiB;AACjB;IACI,aAAa;IACb,SAAS;IACT,mBAAmB;IACnB,eAAe;AACnB;;AAEA;IACI,0BAA0B;IAC1B,iBAAiB;IACjB,mBAAmB;IACnB,gCAAgC;IAChC,eAAe;AACnB;;AAEA,iBAAiB;AACjB;IACI,gBAAgB;IAChB,0BAA0B;IAC1B,mCAAmC;IACnC,6BAA6B;AACjC;;AAEA;IACI,WAAW;IACX,yBAAyB;AAC7B;;AAEA;;IAEI,aAAa;IACb,gBAAgB;IAChB,wCAAwC;AAC5C;;AAEA;IACI,0BAA0B;IAC1B,gBAAgB;IAChB,sBAAsB;IACtB,eAAe;AACnB;;AAEA;IACI,0BAA0B;AAC9B;;AAEA,WAAW;AACX;IACI,qBAAqB;IACrB,iBAAiB;IACjB,mBAAmB;IACnB,eAAe;IACf,gBAAgB;AACpB;;AAEA;IACI,mBAAmB;IACnB,YAAY;AAChB;;AAEA;IACI,mBAAmB;IACnB,YAAY;AAChB;;AAEA;IACI,mBAAmB;IACnB,YAAY;AAChB;;AAEA;IACI,mBAAmB;IACnB,YAAY;AAChB;;AAEA,oBAAoB;AACpB;IACI,eAAe;IACf,gBAAgB;IAChB,mBAAmB;AACvB;;AAEA;IACI,cAAc;AAClB;;AAEA;IACI,cAAc;AAClB;;AAEA,iBAAiB;AACjB;IACI,aAAa;IACb,sBAAsB;IACtB,SAAS;AACb;;AAEA;IACI,0BAA0B;IAC1B,mCAAmC;IACnC,aAAa;IACb,6BAA6B;AACjC;;AAEA;IACI,eAAe;IACf,mBAAmB;IACnB,kBAAkB;IAClB,sBAAsB;AAC1B;;AAEA;IACI,aAAa;IACb,4DAA4D;IAC5D,SAAS;AACb;;AAEA;IACI,aAAa;IACb,2DAA2D;IAC3D,SAAS;IACT,mBAAmB;AACvB;;AAEA;IACI,mFAAmF;IACnF,iCAAiC;IACjC,mCAAmC;IACnC,kBAAkB;IAClB,gCAAgC;AACpC;;AAEA;IACI,cAAc;IACd,eAAe;IACf,gBAAgB;IAChB,sBAAsB;IACtB,kBAAkB;AACtB;;AAEA;IACI,cAAc;IACd,eAAe;IACf,sBAAsB;AAC1B;;AAEA;IACI,0BAA0B;IAC1B,sCAAsC;IACtC,aAAa;IACb,6BAA6B;AACjC;;AAEA;IACI,2BAA2B;IAC3B,gCAAgC;AACpC;;AAEA;IACI,sBAAsB;IACtB,eAAe;IACf,2BAA2B;IAC3B,kBAAkB;AACtB;;AAEA;IACI,gBAAgB;IAChB,kBAAkB;AACtB;;AAEA;IACI,aAAa;IACb,SAAS;IACT,eAAe;IACf,sBAAsB;IACtB,kBAAkB;AACtB;;AAEA;IACI,eAAe;IACf,sBAAsB;AAC1B;;AAEA;IACI,kBAAkB;IAClB,gBAAgB;IAChB,6DAA6D;IAC7D,2CAA2C;IAC3C,6BAA6B;AACjC;;AAEA;IACI,WAAW;IACX,WAAW;IACX,yEAAyE;AAC7E;;AAEA;IACI,aAAa;IACb,eAAe;IACf,QAAQ;IACR,gBAAgB;AACpB;;AAEA;IACI,oBAAoB;IACpB,mBAAmB;IACnB,uBAAuB;IACvB,iBAAiB;IACjB,oBAAoB;IACpB,kCAAkC;IAClC,cAAc;IACd,eAAe;IACf,gBAAgB;AACpB;;AAEA,oBAAoB;AACpB;IACI,0BAA0B;IAC1B,mCAAmC;IACnC,aAAa;IACb,mBAAmB;IACnB,6BAA6B;AACjC;;AAEA;;;IAGI,eAAe;IACf,mBAAmB;IACnB,sBAAsB;AAC1B;;AAEA,UAAU;AACV;IACI,eAAe;IACf,MAAM;IACN,OAAO;IACP,QAAQ;IACR,SAAS;IACT,8BAA8B;IAC9B,aAAa;IACb,mBAAmB;IACnB,uBAAuB;IACvB,aAAa;AACjB;;AAEA;IACI,0BAA0B;IAC1B,sCAAsC;IACtC,UAAU;IACV,gBAAgB;IAChB,gBAAgB;IAChB,gBAAgB;AACpB;;AAEA;IACI,aAAa;IACb,8BAA8B;IAC9B,mBAAmB;IACnB,kBAAkB;IAClB,wCAAwC;AAC5C;;AAEA;IACI,gBAAgB;IAChB,YAAY;IACZ,eAAe;IACf,eAAe;IACf,sBAAsB;AAC1B;;AAEA;IACI,aAAa;AACjB;;AAEA;IACI,aAAa;IACb,yBAAyB;IACzB,SAAS;IACT,kBAAkB;IAClB,qCAAqC;AACzC;;AAEA,aAAa;AACb;IACI,aAAa;IACb,2DAA2D;IAC3D,SAAS;AACb;;AAEA;;;IAGI,WAAW;IACX,aAAa;IACb,iCAAiC;IACjC,sCAAsC;IACtC,eAAe;IACf,6BAA6B;AACjC;;AAEA;;;IAGI,aAAa;IACb,kCAAkC;IAClC,6CAA6C;AACjD;;AAEA,UAAU;AACV;IACI,kBAAkB;IAClB,sCAAsC;IACtC,mBAAmB;AACvB;;AAEA;IACI,mBAAmB;IACnB,cAAc;IACd,yBAAyB;AAC7B;;AAEA;IACI,mBAAmB;IACnB,cAAc;IACd,yBAAyB;AAC7B;;AAEA,YAAY;AACZ;IACI,kBAAkB;IAClB,aAAa;IACb,sBAAsB;AAC1B;;AAEA,eAAe;AACf;IACI;QACI,0BAA0B;IAC9B;;IAEA;QACI,0BAA0B;IAC9B;;IAEA;;QAEI,aAAa;QACb,eAAe;IACnB;AACJ;AACA,mBAAmB;AACnB;IACI,gBAAgB;IAChB,YAAY;IACZ,eAAe;IACf,eAAe;IACf,YAAY;IACZ,kBAAkB;IAClB,6BAA6B;IAC7B,aAAa;AACjB;;AAEA;IACI,2BAA2B;IAC3B,qBAAqB;AACzB;;AAEA;IACI,mBAAmB;IACnB,0BAA0B;AAC9B;;AAEA;IACI,aAAa;IACb,QAAQ;IACR,gBAAgB;IAChB,yBAAyB;AAC7B;;AAEA,8BAA8B;AAC9B;IACI,mBAAmB;AACvB;;AAEA;IACI,aAAa;IACb,sBAAsB;IACtB,SAAS;AACb;;AAEA,6CAA6C;AAC7C;IACI,aAAa;IACb,qCAAqC;IACrC,SAAS;IACT,kBAAkB;AACtB;;AAEA;IACI,sBAAsB,qCAAqC,EAAE;AACjE;AACA;IACI,sBAAsB,qCAAqC,EAAE;AACjE;AACA;IACI,sBAAsB,0BAA0B,EAAE;AACtD;;AAEA,qBAAqB;AACrB;IACI,aAAa;IACb,SAAS;IACT,eAAe;IACf,mBAAmB;IACnB,kBAAkB;IAClB,0BAA0B;IAC1B,wCAAwC;AAC5C;;AAEA;IACI,eAAe;IACf,gBAAgB;IAChB,sBAAsB;IACtB,mBAAmB;AACvB;;AAEA;IACI,iBAAiB;IACjB,iCAAiC;IACjC,sCAAsC;IACtC,eAAe;IACf,0BAA0B;IAC1B,gBAAgB;IAChB,eAAe;IACf,6BAA6B;AACjC;;AAEA;IACI,aAAa;IACb,kCAAkC;IAClC,6CAA6C;AACjD;;AAEA;IACI,0BAA0B;IAC1B,mCAAmC;IACnC,aAAa;IACb,6BAA6B;AACjC;;AAEA;IACI,aAAa;IACb,8BAA8B;IAC9B,uBAAuB;IACvB,SAAS;AACb;;AAEA;IACI,aAAa;IACb,qCAAqC;IACrC,SAAS;IACT,gBAAgB;AACpB;;AAEA;IACI,2BAA2B;IAC3B,kBAAkB;IAClB,aAAa;IACb,kBAAkB;AACtB;;AAEA;IACI,cAAc;IACd,eAAe;IACf,sBAAsB;IACtB,kBAAkB;AACtB;;AAEA;IACI,eAAe;IACf,gBAAgB;IAChB,sBAAsB;AAC1B;;AAEA;IACI,gBAAgB;IAChB,kBAAkB;IAClB,eAAe;IACf,sBAAsB;AAC1B;;AAEA;IACI,qBAAqB;IACrB,iBAAiB;IACjB,eAAe;IACf,sBAAsB;AAC1B","sourcesContent":["/* AdminPages.css */\r\n.admin-page {\r\n    animation: fadeIn 0.3s ease-out;\r\n}\r\n\r\n.page-header {\r\n    margin-bottom: 32px;\r\n}\r\n\r\n.page-header h1 {\r\n    font-size: 28px;\r\n    color: var(--gray-800);\r\n    margin-bottom: 8px;\r\n}\r\n\r\n.page-header p {\r\n    color: var(--gray-500);\r\n    margin-bottom: 20px;\r\n}\r\n\r\n.page-kicker {\r\n    display: inline-flex;\r\n    align-items: center;\r\n    padding: 6px 12px;\r\n    margin-bottom: 10px;\r\n    border-radius: 999px;\r\n    background: rgba(99, 102, 241, 0.12);\r\n    color: var(--primary-color);\r\n    font-size: 12px;\r\n    font-weight: 700;\r\n    letter-spacing: 0.04em;\r\n    text-transform: uppercase;\r\n}\r\n\r\n/* Stats Badges */\r\n.users-stats, .formateurs-stats {\r\n    display: flex;\r\n    gap: 16px;\r\n    margin-bottom: 24px;\r\n    flex-wrap: wrap;\r\n}\r\n\r\n.stat-badge {\r\n    background: var(--surface);\r\n    padding: 8px 16px;\r\n    border-radius: 20px;\r\n    box-shadow: var(--box-shadow-sm);\r\n    font-size: 14px;\r\n}\r\n\r\n/* Table Styles */\r\n.table-container {\r\n    overflow-x: auto;\r\n    background: var(--surface);\r\n    border-radius: var(--border-radius);\r\n    box-shadow: var(--box-shadow);\r\n}\r\n\r\n.data-table {\r\n    width: 100%;\r\n    border-collapse: collapse;\r\n}\r\n\r\n.data-table th,\r\n.data-table td {\r\n    padding: 16px;\r\n    text-align: left;\r\n    border-bottom: 1px solid var(--gray-200);\r\n}\r\n\r\n.data-table th {\r\n    background: var(--gray-50);\r\n    font-weight: 600;\r\n    color: var(--gray-600);\r\n    font-size: 14px;\r\n}\r\n\r\n.data-table tbody tr:hover {\r\n    background: var(--gray-50);\r\n}\r\n\r\n/* Badges */\r\n.badge {\r\n    display: inline-block;\r\n    padding: 4px 12px;\r\n    border-radius: 20px;\r\n    font-size: 12px;\r\n    font-weight: 600;\r\n}\r\n\r\n.badge-admin {\r\n    background: #8B5CF6;\r\n    color: white;\r\n}\r\n\r\n.badge-formateur {\r\n    background: #3B82F6;\r\n    color: white;\r\n}\r\n\r\n.badge-etudiant {\r\n    background: #10B981;\r\n    color: white;\r\n}\r\n\r\n.badge-success {\r\n    background: #10B981;\r\n    color: white;\r\n}\r\n\r\n/* Password Status */\r\n.password-status {\r\n    font-size: 12px;\r\n    padding: 4px 8px;\r\n    border-radius: 12px;\r\n}\r\n\r\n.has-password {\r\n    color: #10B981;\r\n}\r\n\r\n.no-password {\r\n    color: #EF4444;\r\n}\r\n\r\n/* Modules Grid */\r\n.modules-grid {\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 32px;\r\n}\r\n\r\n.niveau-section {\r\n    background: var(--surface);\r\n    border-radius: var(--border-radius);\r\n    padding: 24px;\r\n    box-shadow: var(--box-shadow);\r\n}\r\n\r\n.niveau-title {\r\n    font-size: 20px;\r\n    margin-bottom: 20px;\r\n    padding-left: 16px;\r\n    border-left: 4px solid;\r\n}\r\n\r\n.module-cards {\r\n    display: grid;\r\n    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));\r\n    gap: 16px;\r\n}\r\n\r\n.module-overview-strip {\r\n    display: grid;\r\n    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));\r\n    gap: 14px;\r\n    margin-bottom: 24px;\r\n}\r\n\r\n.overview-card {\r\n    background: linear-gradient(180deg, rgba(255,255,255,0.96), rgba(248,250,252,0.96));\r\n    border: 1px solid var(--gray-200);\r\n    border-radius: var(--border-radius);\r\n    padding: 16px 18px;\r\n    box-shadow: var(--box-shadow-sm);\r\n}\r\n\r\n.overview-value {\r\n    display: block;\r\n    font-size: 20px;\r\n    font-weight: 800;\r\n    color: var(--gray-900);\r\n    margin-bottom: 4px;\r\n}\r\n\r\n.overview-label {\r\n    display: block;\r\n    font-size: 13px;\r\n    color: var(--gray-500);\r\n}\r\n\r\n.module-card {\r\n    background: var(--gray-50);\r\n    border-radius: var(--border-radius-sm);\r\n    padding: 16px;\r\n    transition: var(--transition);\r\n}\r\n\r\n.module-card:hover {\r\n    transform: translateY(-2px);\r\n    box-shadow: var(--box-shadow-md);\r\n}\r\n\r\n.module-code {\r\n    font-family: monospace;\r\n    font-size: 12px;\r\n    color: var(--primary-color);\r\n    margin-bottom: 8px;\r\n}\r\n\r\n.module-name {\r\n    font-weight: 600;\r\n    margin-bottom: 8px;\r\n}\r\n\r\n.module-meta {\r\n    display: flex;\r\n    gap: 16px;\r\n    font-size: 12px;\r\n    color: var(--gray-500);\r\n    margin-bottom: 8px;\r\n}\r\n\r\n.module-desc {\r\n    font-size: 13px;\r\n    color: var(--gray-600);\r\n}\r\n\r\n.admin-module-detail {\r\n    position: relative;\r\n    overflow: hidden;\r\n    background: linear-gradient(180deg, #ffffff 0%, #f8fafc 100%);\r\n    border: 1px solid rgba(148, 163, 184, 0.22);\r\n    box-shadow: var(--box-shadow);\r\n}\r\n\r\n.module-card-accent {\r\n    height: 5px;\r\n    width: 100%;\r\n    background: linear-gradient(90deg, #2563eb 0%, #0ea5e9 50%, #22c55e 100%);\r\n}\r\n\r\n.component-chip-row {\r\n    display: flex;\r\n    flex-wrap: wrap;\r\n    gap: 8px;\r\n    margin-top: 10px;\r\n}\r\n\r\n.component-chip {\r\n    display: inline-flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    padding: 6px 10px;\r\n    border-radius: 999px;\r\n    background: rgba(37, 99, 235, 0.1);\r\n    color: #1d4ed8;\r\n    font-size: 12px;\r\n    font-weight: 700;\r\n}\r\n\r\n/* Assignment Form */\r\n.assignment-form {\r\n    background: var(--surface);\r\n    border-radius: var(--border-radius);\r\n    padding: 24px;\r\n    margin-bottom: 32px;\r\n    box-shadow: var(--box-shadow);\r\n}\r\n\r\n.assignment-form h2,\r\n.assignments-list h2,\r\n.enrollments-list h2 {\r\n    font-size: 18px;\r\n    margin-bottom: 20px;\r\n    color: var(--gray-800);\r\n}\r\n\r\n/* Modal */\r\n.modal-overlay {\r\n    position: fixed;\r\n    top: 0;\r\n    left: 0;\r\n    right: 0;\r\n    bottom: 0;\r\n    background: rgba(0, 0, 0, 0.5);\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    z-index: 1000;\r\n}\r\n\r\n.modal-content {\r\n    background: var(--surface);\r\n    border-radius: var(--border-radius-lg);\r\n    width: 90%;\r\n    max-width: 500px;\r\n    max-height: 90vh;\r\n    overflow-y: auto;\r\n}\r\n\r\n.modal-header {\r\n    display: flex;\r\n    justify-content: space-between;\r\n    align-items: center;\r\n    padding: 20px 24px;\r\n    border-bottom: 1px solid var(--gray-200);\r\n}\r\n\r\n.modal-close {\r\n    background: none;\r\n    border: none;\r\n    font-size: 24px;\r\n    cursor: pointer;\r\n    color: var(--gray-500);\r\n}\r\n\r\n.modal-body {\r\n    padding: 24px;\r\n}\r\n\r\n.modal-footer {\r\n    display: flex;\r\n    justify-content: flex-end;\r\n    gap: 12px;\r\n    padding: 20px 24px;\r\n    border-top: 1px solid var(--gray-200);\r\n}\r\n\r\n/* Form Row */\r\n.form-row {\r\n    display: grid;\r\n    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));\r\n    gap: 16px;\r\n}\r\n\r\n.form-input,\r\n.form-select,\r\n.form-textarea {\r\n    width: 100%;\r\n    padding: 12px;\r\n    border: 2px solid var(--gray-200);\r\n    border-radius: var(--border-radius-sm);\r\n    font-size: 14px;\r\n    transition: var(--transition);\r\n}\r\n\r\n.form-input:focus,\r\n.form-select:focus,\r\n.form-textarea:focus {\r\n    outline: none;\r\n    border-color: var(--primary-color);\r\n    box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.1);\r\n}\r\n\r\n/* Alert */\r\n.alert {\r\n    padding: 12px 16px;\r\n    border-radius: var(--border-radius-sm);\r\n    margin-bottom: 20px;\r\n}\r\n\r\n.alert-success {\r\n    background: #ecfdf5;\r\n    color: #047857;\r\n    border: 1px solid #a7f3d0;\r\n}\r\n\r\n.alert-error {\r\n    background: #fef2f2;\r\n    color: #dc2626;\r\n    border: 1px solid #fecaca;\r\n}\r\n\r\n/* Loading */\r\n.loading-text {\r\n    text-align: center;\r\n    padding: 60px;\r\n    color: var(--gray-500);\r\n}\r\n\r\n/* Responsive */\r\n@media (max-width: 768px) {\r\n    .form-row {\r\n        grid-template-columns: 1fr;\r\n    }\r\n    \r\n    .module-cards {\r\n        grid-template-columns: 1fr;\r\n    }\r\n    \r\n    .data-table th,\r\n    .data-table td {\r\n        padding: 12px;\r\n        font-size: 13px;\r\n    }\r\n}\r\n/* Action buttons */\r\n.btn-icon {\r\n    background: none;\r\n    border: none;\r\n    font-size: 18px;\r\n    cursor: pointer;\r\n    padding: 6px;\r\n    border-radius: 8px;\r\n    transition: var(--transition);\r\n    margin: 0 2px;\r\n}\r\n\r\n.btn-icon:hover {\r\n    background: var(--gray-100);\r\n    transform: scale(1.1);\r\n}\r\n\r\n.btn-icon.btn-danger:hover {\r\n    background: #fee2e2;\r\n    color: var(--danger-color);\r\n}\r\n\r\n.module-actions {\r\n    display: flex;\r\n    gap: 8px;\r\n    margin-top: 12px;\r\n    justify-content: flex-end;\r\n}\r\n\r\n/* Add to table actions cell */\r\n.data-table td:last-child {\r\n    white-space: nowrap;\r\n}\r\n\r\n.modules-admin-list {\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 20px;\r\n}\r\n\r\n/* Grille 4 colonnes pour les modules admin */\r\n.modules-admin-grid {\r\n    display: grid;\r\n    grid-template-columns: repeat(4, 1fr);\r\n    gap: 20px;\r\n    align-items: start;\r\n}\r\n\r\n@media (max-width: 1400px) {\r\n    .modules-admin-grid { grid-template-columns: repeat(3, 1fr); }\r\n}\r\n@media (max-width: 1000px) {\r\n    .modules-admin-grid { grid-template-columns: repeat(2, 1fr); }\r\n}\r\n@media (max-width: 640px) {\r\n    .modules-admin-grid { grid-template-columns: 1fr; }\r\n}\r\n\r\n/* Barre de filtres */\r\n.filters-bar {\r\n    display: flex;\r\n    gap: 10px;\r\n    flex-wrap: wrap;\r\n    align-items: center;\r\n    padding: 12px 16px;\r\n    background: var(--gray-50);\r\n    border-bottom: 1px solid var(--gray-200);\r\n}\r\n\r\n.filters-bar label {\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    color: var(--gray-600);\r\n    white-space: nowrap;\r\n}\r\n\r\n.filter-select {\r\n    padding: 7px 12px;\r\n    border: 2px solid var(--gray-200);\r\n    border-radius: var(--border-radius-sm);\r\n    font-size: 13px;\r\n    background: var(--surface);\r\n    min-width: 160px;\r\n    cursor: pointer;\r\n    transition: var(--transition);\r\n}\r\n\r\n.filter-select:focus {\r\n    outline: none;\r\n    border-color: var(--primary-color);\r\n    box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.1);\r\n}\r\n\r\n.admin-module-detail {\r\n    background: var(--surface);\r\n    border-radius: var(--border-radius);\r\n    padding: 20px;\r\n    box-shadow: var(--box-shadow);\r\n}\r\n\r\n.module-card-head {\r\n    display: flex;\r\n    justify-content: space-between;\r\n    align-items: flex-start;\r\n    gap: 16px;\r\n}\r\n\r\n.resource-type-grid {\r\n    display: grid;\r\n    grid-template-columns: repeat(4, 1fr);\r\n    gap: 12px;\r\n    margin-top: 16px;\r\n}\r\n\r\n.resource-type-cell {\r\n    background: var(--gray-100);\r\n    border-radius: 8px;\r\n    padding: 10px;\r\n    text-align: center;\r\n}\r\n\r\n.resource-type-label {\r\n    display: block;\r\n    font-size: 12px;\r\n    color: var(--gray-600);\r\n    margin-bottom: 4px;\r\n}\r\n\r\n.resource-type-count {\r\n    font-size: 20px;\r\n    font-weight: 700;\r\n    color: var(--gray-900);\r\n}\r\n\r\n.resource-mini-list {\r\n    margin: 12px 0 0;\r\n    padding-left: 18px;\r\n    font-size: 14px;\r\n    color: var(--gray-700);\r\n}\r\n\r\n.resource-mini-list .r-cat {\r\n    display: inline-block;\r\n    min-width: 4.5rem;\r\n    font-size: 12px;\r\n    color: var(--gray-500);\r\n}\r\n"],"sourceRoot":""}]);
